using namespace std;

struct File {
    int id;
    string name;
    int size;
};

class FileManager {
private:
    vector<File> files;
    int nextId;

public:
    FileManager() : nextId(1) {}

    void createFile(const string& name, int size) {
        File newFile;
        newFile.id = nextId++;
        newFile.name = name;
        newFile.size = size;
        files.push_back(newFile);
        cout << "File created with ID: " << newFile.id << endl;
    }

    void deleteFile(int id) {
        auto it = find_if(files.begin(), files.end(), [id](const File& file) {
            return file.id == id;
        });

        if (it != files.end()) {
            files.erase(it);
            cout << "File with ID " << id << " deleted." << endl;
        } else {
            cout << "File with ID " << id << " not found." << endl;
        }
    }

    void listFiles() {
        if (files.empty()) {
            cout << "No files found." << endl;
            return;
        }

        cout << "Files:" << endl;
        for (const auto& file : files) {
            cout << "ID: " << file.id << ", Name: " << file.name << ", Size: " << file.size << " KB" << endl;
        }
    }
};

int main() {
    FileManager fm;
    int choice;
    string name;
    int size, id;

    while (true) {
        cout << "\nFile Management System\n";
        cout << "1. Create File\n";
        cout << "2. Delete File\n";
        cout << "3. List Files\n";
        cout << "4. Exit\n";
