/// Calculates the final price after applying a discount to the original price.
///
/// # Arguments
///
/// * `original_price` - The original price before discount (f64).
/// * `discount_percentage` - The discount percentage to apply (f64).
///
/// # Returns
///
/// The final price after applying the discount (f64).
///
/// # Example
///
/// ```
/// let final_price = calculate_discount(100.0, 20.0);
/// assert_eq!(final_price, 80.0);
/// ```
fn calculate_discount(original_price: f64, discount_percentage: f64) -> f64 {
    // Calculate the discount amount by multiplying the original price by the discount percentage.
    let discount_amount = original_price * (discount_percentage / 100.0);

    // Subtract the discount amount from the original price to get the final price.
    original_price - discount_amount
}
