mod config_loader {
  use std::collections::HashMap;
  use std::fs;
  use std::io;

  /// Loads configuration from a file and returns a HashMap of key-value pairs.
  ///
  /// # Arguments
  /// * `file_path` - Path to the configuration file.
  ///
  /// # Returns
  /// * `Result<HashMap<String, String>, io::Error>` - Parsed configuration or an error.
  pub fn load_configuration(file_path: &str) -> io::Result<HashMap<String, String>> {
    let file_contents = fs::read_to_string(file_path)?;
    let mut config_map = HashMap::new();

    for line in file_contents.lines() {
      let trimmed_line = line.trim();
      if trimmed_line.is_empty() || trimmed_line.starts_with('#') {
        continue;
      }

      let parts: Vec<&str> = trimmed_line.split('=').map(|s| s.trim()).collect();
      if parts.len() != 2 {
        return Err(io::Error::new(
          io::ErrorKind::InvalidData,
          "Invalid configuration format",
        ));
      }

